{{Concept | Name=Genome Engine | Guid=3015-13465 | Deck=Genome Engine is a game engine created by the German game developer Piranha Bytes. It has been used in their RPGs, including Gothic 3, Gothic 3: Forsaken Gods, Risen series, and also in Elex games. The engine was first released in 2006. | Characters= | Concepts=Concepts/Aberrant_A_I_Behaviour,Concepts/Action_RPG,Concepts/Aggro,Concepts/Alchemy,Concepts/Ambush,Concepts/Archery,Concepts/Artificial_Intelligence,Concepts/Attributes,Concepts/Blacksmith,Concepts/Blunt_Weapons,Concepts/Bribery,Concepts/Climbing,Concepts/Cutscene,Concepts/Danger_Zone,Concepts/Dark_Humor,Concepts/Day_Night_Cycle,Concepts/Dialogue_Tree,Concepts/Dinosaur,Concepts/Drowning,Concepts/Drug_Use,Concepts/Enemy_Health_Indicator,Concepts/Experience_Points,Concepts/Fetch_Quest,Concepts/Flying_Enemies,Concepts/From_Zero_to_Hero,Concepts/Healing_Food,Concepts/Health,Concepts/Infinite_Pockets,Concepts/Interactive_Environments,Concepts/Inventory,Concepts/Kill_Quest,Concepts/Knock_Back,Concepts/Lawbreaking,Concepts/Level_Up,Concepts/Lock_Picking,Concepts/Loot_Gathering,Concepts/Loud_Ambient_Noises,Concepts/Magic,Concepts/Melee,Concepts/Minigame,Concepts/Mining,Concepts/Monster_Infighting,Concepts/Morality_System,Concepts/Nameless_Protagonist,Concepts/New_Guy,Concepts/Non_Player_Character,Concepts/Objectiveless_beginning,Concepts/Open_World,Concepts/Orc,Concepts/Perk,Concepts/Pickpocketing,Concepts/Pirate,Concepts/Plummeting_Enemies,Concepts/Polygonal_3D,Concepts/Questing,Concepts/Rain,Concepts/Reading,Concepts/Real_Time_Combat,Concepts/Religion,Concepts/Rivaling_Factions,Concepts/Role_Playing_Shooter,Concepts/Sandbox,Concepts/Scripted_Events,Concepts/Searching_Corpses,Concepts/Side_Quest,Concepts/Sitting_Down,Concepts/Skeletons,Concepts/Skinning,Concepts/Slashing_Weapons,Concepts/Slavery,Concepts/Sleep_Disruption,Concepts/Sleeping,Concepts/Sleeping_Enemies,Concepts/Smithing,Concepts/Spellcaster,Concepts/Spiders,Concepts/Stealth,Concepts/Summoners,Concepts/Survival,Concepts/Sword_and_Sorcery,Concepts/Theft,Concepts/Third_Person_Perspective,Concepts/Urinating,Concepts/Voice_Acting,Concepts/Waking_Up_at_Beginning,Concepts/Weather,Concepts/Wolf,Concepts/ZenGin_engine | Franchises= | Games=Games/ELEX,Games/ELEX_II,Games/Gothic_3,Games/Gothic_3_Forsaken_Gods,Games/Risen,Games/Risen_2_Dark_Waters,Games/Risen_3_Titan_Lords | Locations=Locations/Castle,Locations/City,Locations/Desert,Locations/Farm,Locations/Forest,Locations/Fortress,Locations/Home,Locations/House,Locations/Island,Locations/Lake,Locations/Mine,Locations/Ocean,Locations/River,Locations/Rural_Area,Locations/Shack,Locations/Shanty_Town,Locations/Stairway,Locations/Swamp,Locations/Temple,Locations/Town,Locations/Volcanic_Terrain,Locations/Volcano | Objects=Objects/Axe,Objects/Beard,Objects/Boardwalk,Objects/Bottle,Objects/Bow,Objects/Campfire,Objects/Cauldron,Objects/Corpse,Objects/Crossbow,Objects/Crowbar,Objects/Facial_Hair,Objects/Flowers,Objects/Forge_4736,Objects/Frying_Pan,Objects/Glass,Objects/Grass,Objects/Grenade,Objects/Grenade_Launcher,Objects/Gun,Objects/Health_Potion,Objects/Lightning,Objects/Mana_Potion,Objects/Meat,Objects/Ore,Objects/Pelt,Objects/Pickaxe,Objects/Potion,Objects/Red_Potion,Objects/Shield,Objects/Ship,Objects/Shotgun,Objects/Stinger_4153,Objects/Stone,Objects/Sword,Objects/Table,Objects/Throne,Objects/Torch,Objects/Trail,Objects/Tree,Objects/Vial,Objects/Water,Objects/Water_Bottle,Objects/Wood,Objects/Wooden_Chair | People= | Image=https://www.giantbomb.com/a/uploads/scale_super/1/15693/1249379-446660.jpg}}
